sql:
SELECT flight_id
FROM flight_reports
WHERE report_type = 'post-flight' AND report_date >= '2023-10-01';

external_knowledge:
- 'Completed trips' refer to flights that have a status of 'completed'.;
- The 'two longest completed trips' are determined based on the 'flight_distance' column, sorted in descending order.;
- 'Details' include the unique identifier (flight_id), flight number, and the departure and arrival airports.

sql:
SELECT flight_id, SUM(flight_distance) as total_flight_distance
FROM flights
GROUP BY flight_id;

